// Parse data dari webhook PHP
const data = $input.item.json.body || $input.item.json;

return {
  json: {
    timestamp: data.timestamp,
    reminderType: data.reminder_type,
    totalGuru: data.total_belum_presensi,
    guruList: data.guru_list,
    adminAlert: data.admin_alert,
    adminPhone: data.admin_phone
  }
};

// Ambil data guru dari loop
const allData = $input.first().json;
const guruList = allData.guruList;
const currentIndex = $input.context.noItemsLeft ? 0 : $input.context.currentRunIndex;
const guru = guruList[currentIndex];
const reminderType = allData.reminderType;

// Template pesan berdasarkan jenis reminder
let message = '';

if (reminderType === 'first') {
  // Pengingat pertama (08:00)
  message = `🔔 *Pengingat Presensi*

Halo *${guru.nama}*,

Anda belum melakukan presensi hari ini.
Mohon segera isi presensi melalui:
👉 https://kelolasekolah.web.id

Terima kasih.
_Sistem GeoPresensi Sekolah_`;

} else if (reminderType === 'second') {
  // Pengingat kedua (09:00)
  message = `⚠️ *Pengingat Presensi (Kedua)*

Halo *${guru.nama}*,

Anda masih belum melakukan presensi hari ini.
Mohon segera isi presensi:
👉 https://kelolasekolah.web.id

Terima kasih.
_Sistem GeoPresensi Sekolah_`;

} else if (reminderType === 'final') {
  // Pengingat terakhir (10:00)
  message = `🚨 *Pengingat Presensi (Terakhir)*

Halo *${guru.nama}*,

Ini adalah pengingat terakhir.
Anda belum melakukan presensi hari ini.

Mohon SEGERA isi presensi:
👉 https://kelolasekolah.web.id

Jika ada kendala, hubungi admin.
_Sistem GeoPresensi Sekolah_`;
} else {
  // Manual atau default
  message = `🔔 *Pengingat Presensi*

Halo *${guru.nama}*,

Anda belum melakukan presensi hari ini.
Mohon segera isi presensi melalui:
👉 https://kelolasekolah.web.id

Terima kasih.
_Sistem GeoPresensi Sekolah_`;
}

// Format nomor HP (konversi 08xxx ke 628xxx jika perlu)
let phone = guru.no_hp;
if (phone.startsWith('0')) {
  phone = '62' + phone.substring(1);
}

return {
  json: {
    phone: phone,
    message: message,
    nama: guru.nama,
    reminderType: reminderType
  }
};

// Cek apakah perlu kirim notifikasi ke admin (jam 10:00)
const firstItem = $input.first().json;
const adminAlert = firstItem.adminAlert;
const adminPhone = firstItem.adminPhone;

if (adminAlert && adminPhone) {
  return {
    json: {
      sendToAdmin: true,
      adminPhone: adminPhone,
      totalGuru: firstItem.totalGuru,
      guruList: firstItem.guruList,
      timestamp: firstItem.timestamp
    }
  };
} else {
  return {
    json: {
      sendToAdmin: false,
      message: 'Admin alert not needed (not 10:00 or no admin phone)'
    }
  };
}

// Format pesan untuk admin
const totalGuru = $json.totalGuru;
const guruList = $json.guruList;
const timestamp = $json.timestamp;

// Buat list nama guru
let namaGuru = guruList.map((g, i) => `${i+1}. ${g.nama}`).join('\n');

const message = `📊 *Laporan Presensi - 10:00 WIB*

⚠️ Total guru belum presensi: *${totalGuru} orang*

Daftar guru:
${namaGuru}

Pengingat terakhir telah dikirim.
Mohon tindak lanjut.

_Sistem GeoPresensi Sekolah_
_${timestamp}_`;

// Format nomor HP admin
let phone = $json.adminPhone;
if (phone.startsWith('0')) {
  phone = '62' + phone.substring(1);
}

return {
  json: {
    phone: phone,
    message: message
  }
};
